// LT Safe Logging Test - static payload
// No booking, no calendar, no SMS - dashboard logging only
//
// The API key is read from n8n environment variable INTERNAL_API_KEY.
// If not set in n8n Cloud Settings > Variables, this will fail with 403.

const apiKey = $env.INTERNAL_API_KEY || '';

if (!apiKey) {
  return [{
    json: {
      error: 'INTERNAL_API_KEY not set in n8n environment variables',
      fix: 'Go to n8n Cloud Settings > Variables and set INTERNAL_API_KEY to the value from Render Dashboard',
      blocked: true
    }
  }];
}

return [{
  json: {
    apiKey: apiKey,
    payload: {
      tenantId: '7d82ab25-e991-4d13-b4ac-846865f8b85a',
      customerPhone: '+37067577829',
      inboundBody: 'LT safe logging test - no booking. Sveiki, noriu pasitikrinti ar sistema veikia.',
      outboundBody: 'LT safe logging test - sistema veikia. Jokia registracija nesukurta.',
      bookingDetected: false,
      source: 'sms'
    }
  }
}];

const response = $input.first().json;

const success = response.success === true;
const httpError = response.error || response.message || null;

return [{
  json: {
    testResult: success ? 'PASSED' : 'FAILED',
    conversationId: response.conversationId || null,
    messagesLogged: response.messagesLogged || 0,
    bookingDetected: response.bookingDetected || false,
    error: httpError,
    rawResponse: response,
    verifiedAt: new Date().toISOString(),
    usaSafe: true,
    bookingTriggered: false,
    calendarTriggered: false
  }
}];
